     1→'use client';
     2→
     3→import { Fragment, useState, useEffect } from 'react';
     4→import Link from 'next/link';
     5→import { usePathname } from 'next/navigation';
     6→import { siteConfig } from '../../site.config';
     7→import type { NavChildItem } from '../../site.config';
     8→import ThemeToggle from './ThemeToggle';
     9→import LanguageSwitch from './LanguageSwitch';
    10→import Search from '@/components/Search';
    11→import { useLanguage } from '@/components/LanguageProvider';
    12→import { resolveLocaleValue } from '@/lib/i18n';
    13→import { TranslationKey } from '@/i18n/translations';
    14→
    15→interface NavItem {
    16→  name: string;
    17→  slug: string;
    18→}
    19→
    20→interface NavbarProps {
    21→  seriesList?: NavItem[];
    22→  booksList?: NavItem[];
    23→}
    24→
    25→// Map from nav URL to feature key
    26→const FEATURE_URLS: Partial<Record<string, keyof typeof siteConfig.features>> = {
    27→  '/posts': 'posts',
    28→  '/flows': 'flow',
    29→  '/notes': 'flow',
    30→  '/graph': 'flow',
    31→  '/series': 'series',
    32→  '/books': 'books',
    33→};
    34→
    35→export default function Navbar({ seriesList = [], booksList = [] }: NavbarProps) {
    36→  const { t, language } = useLanguage();
    37→  const pathname = usePathname();
    38→  const [isMenuOpen, setIsMenuOpen] = useState(false);
    39→  const [isScrolled, setIsScrolled] = useState(false);
    40→  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
    41→
    42→  const navItems = [...siteConfig.nav]
    43→    .filter(item => {
    44→      const featureKey = FEATURE_URLS[item.url];
    45→      if (!featureKey) return true; // not a feature-gated item, always show
    46→      return siteConfig.features?.[featureKey]?.enabled !== false;
    47→    })
    48→    .sort((a, b) => a.weight - b.weight);
    49→
    50→  const getLabel = (name: string, url: string): string => {
    51→    const featureKey = FEATURE_URLS[url];
    52→    if (featureKey && siteConfig.features?.[featureKey]?.name) {
    53→      return resolveLocaleValue(siteConfig.features[featureKey].name, language);
    54→    }
    55→    const key = name.toLowerCase() as TranslationKey;
    56→    const translated = t(key);
    57→    return translated !== key ? translated : name;
    58→  };
    59→
    60→  function isActive(url: string): boolean {
    61→    if (url === '/flows') {
    62→      return pathname.startsWith('/flows') || pathname.startsWith('/notes') || pathname.startsWith('/graph');
    63→    }
    64→    if (url === '/') return pathname === '/';
    65→    return pathname.startsWith(url);
    66→  }
    67→
    68→  // Scroll-aware transparency
    69→  useEffect(() => {
    70→    const handleScroll = () => setIsScrolled(window.scrollY > 8);
    71→    handleScroll(); // sync with scroll position at mount (e.g. after refresh while scrolled)
    72→    window.addEventListener('scroll', handleScroll, { passive: true });
    73→    return () => window.removeEventListener('scroll', handleScroll);
    74→  }, []);
    75→
    76→  function closeMenu() {
    77→    setIsMenuOpen(false);
    78→    setOpenDropdown(null);
    79→  }
    80→
    81→  // Prevent body scroll when menu is open
    82→  useEffect(() => {
    83→    if (isMenuOpen) {
    84→      document.body.style.overflow = 'hidden';
    85→    } else {
    86→      document.body.style.overflow = '';
    87→    }
    88→    return () => {
    89→      document.body.style.overflow = '';
    90→    };
    91→  }, [isMenuOpen]);
    92→
    93→  return (
    94→    <nav className={`fixed top-0 left-0 w-full z-50 border-b transition-all duration-300 ${
    95→      isScrolled
    96→        ? 'border-muted/10 bg-background/90 backdrop-blur-md shadow-sm'
    97→        : 'border-transparent bg-transparent'
    98→    }`}>
    99→      <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
   100→        <Link
   101→          href="/"
   102→          className="flex items-center gap-3 text-xl font-serif font-bold text-heading hover:text-accent transition-colors duration-200"
   103→        >
   104→          {siteConfig.logo?.src ? (
   105→            // eslint-disable-next-line @next/next/no-img-element
   106→            <img
   107→              src={siteConfig.logo.src}
   108→              alt=""
   109→              className="h-8 w-auto"
   110→            />
   111→          ) : (
   112→            <svg
   113→              viewBox="0 0 32 32"
   114→              className="w-8 h-8 text-accent"
   115→              fill="none"
   116→              stroke="currentColor"
   117→              strokeWidth="2"
   118→              strokeLinecap="round"
   119→              strokeLinejoin="round"
   120→              aria-hidden="true"
   121→            >
   122→              <path d="M16 4 L7 28" />
   123→              <path d="M16 4 L25 28" />
   124→              <path d="M11.5 18 H 20.5" />
   125→              <path d="M20.5 18 Q 26 14 26 8 Q 23 12 20.5 18" fill="currentColor" stroke="none" />
   126→            </svg>
   127→          )}
   128→          <span>{resolveLocaleValue(siteConfig.title, language)}</span>
   129→        </Link>
   130→
   131→        <div className="flex items-center gap-4 md:gap-6">
   132→          <div className="hidden md:flex items-center gap-6">
   133→            {navItems.map((item) => {
   134→              const isExternal = !!('external' in item && item.external);
   135→              const Component = isExternal ? 'a' : Link;
   136→              const props = isExternal ? { target: "_blank", rel: "noopener noreferrer" } : {};
   137→              const active = isActive(item.url);
   138→
   139→              if (item.url === '/books' && booksList.length > 0) {
   140→                return (
   141→                  <div key={item.url} className="relative group">
   142→                    <Link
   143→                      href={item.url}
   144→                      className={`text-sm font-sans font-medium no-underline transition-colors duration-200 flex items-center gap-1 py-4 ${
   145→                        active ? 'text-accent' : 'text-foreground/80 hover:text-heading'
   146→                      }`}
   147→                    >
   148→                      {getLabel(item.name, item.url)}
   149→                      <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="opacity-50 group-hover:rotate-180 transition-transform">
   150→                        <path d="M6 9l6 6 6-6"/>
   151→                      </svg>
   152→                    </Link>
   153→                    <div className="absolute top-full left-0 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 min-w-[200px] max-h-[70vh] overflow-y-auto">
   154→                      <div className="bg-background/95 backdrop-blur-md border border-muted/10 rounded-xl shadow-xl p-2 flex flex-col gap-1 animate-slide-down">
   155→                        {booksList.map(b => (
   156→                          <Link
   157→                            key={b.slug}
   158→                            href={`/books/${b.slug}`}
   159→                            className="block px-4 py-2.5 text-sm text-foreground/80 hover:text-accent hover:bg-muted/5 rounded-lg transition-colors no-underline whitespace-nowrap"
   160→                          >
   161→                            {b.name}
   162→                          </Link>
   163→                        ))}
   164→                        <div className="h-px bg-muted/10 my-1"></div>
   165→                        <Link
   166→                          href="/books"
   167→                          className="block px-4 py-2 text-xs font-bold uppercase tracking-widest text-muted hover:text-accent hover:bg-muted/5 rounded-lg transition-colors no-underline"
   168→                        >
   169→                          {t('all_books')} →
   170→                        </Link>
   171→                      </div>
   172→                    </div>
   173→                  </div>
   174→                );
   175→              }
   176→
   177→              if (item.url === '/series' && seriesList.length > 0) {
   178→                return (
   179→                  <div key={item.url} className="relative group">
   180→                    <Link
   181→                      href={item.url}
   182→                      className={`text-sm font-sans font-medium no-underline transition-colors duration-200 flex items-center gap-1 py-4 ${
   183→                        active ? 'text-accent' : 'text-foreground/80 hover:text-heading'
   184→                      }`}
   185→                    >
   186→                      {getLabel(item.name, item.url)}
   187→                      <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="opacity-50 group-hover:rotate-180 transition-transform">
   188→                        <path d="M6 9l6 6 6-6"/>
   189→                      </svg>
   190→                    </Link>
   191→                    <div className="absolute top-full left-0 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 min-w-[200px] max-h-[70vh] overflow-y-auto">
   192→                      <div className="bg-background/95 backdrop-blur-md border border-muted/10 rounded-xl shadow-xl p-2 flex flex-col gap-1 animate-slide-down">
   193→                        {seriesList.map(s => (
   194→                          <Link
   195→                            key={s.slug}
   196→                            href={`/series/${s.slug}`}
   197→                            className="block px-4 py-2.5 text-sm text-foreground/80 hover:text-accent hover:bg-muted/5 rounded-lg transition-colors no-underline whitespace-nowrap"
   198→                          >
   199→                            {s.name}
   200→                          </Link>
   201→                        ))}
   202→                        <div className="h-px bg-muted/10 my-1"></div>
   203→                        <Link
   204→                          href="/series"
   205→                          className="block px-4 py-2 text-xs font-bold uppercase tracking-widest text-muted hover:text-accent hover:bg-muted/5 rounded-lg transition-colors no-underline"
   206→                        >
   207→                          {t('all_series')} →
   208→                        </Link>
   209→                      </div>
   210→                    </div>
   211→                  </div>
   212→                );
   213→              }
   214→
   215→              // Static children dropdown (e.g., "More")
   216→              if (item.children && item.children.length > 0) {
   217→                const childActive = item.children.some(c => c.url && pathname.startsWith(c.url));
   218→                return (
   219→                  <div key={item.url || item.name} className="relative group">
   220→                    <button
   221→                      type="button"
   222→                      className={`text-sm font-sans font-medium transition-colors duration-200 flex items-center gap-1 py-4 bg-transparent border-0 cursor-pointer ${
   223→                        childActive ? 'text-accent' : 'text-foreground/80 hover:text-heading'
   224→                      }`}
   225→                    >
   226→                      {getLabel(item.name, item.url)}
   227→                      <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="opacity-50 group-hover:rotate-180 transition-transform">
   228→                        <path d="M6 9l6 6 6-6"/>
   229→                      </svg>
   230→                    </button>
   231→                    <div className="absolute top-full right-0 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 min-w-[160px]">
   232→                      <div className="bg-background/95 backdrop-blur-md border border-muted/10 rounded-xl shadow-xl p-2 flex flex-col gap-1 animate-slide-down">
   233→                        {item.children.map((child: NavChildItem) => {
   234→                          const ChildComp = child.external ? 'a' : Link;
   235→                          const childProps = child.external ? { target: '_blank', rel: 'noopener noreferrer' } : {};
   236→                          return (
   237→                            <Fragment key={child.url}>
   238→                              {child.dividerBefore && <div className="h-px bg-muted/10 my-1" />}
   239→                              <ChildComp
   240→                                href={child.url}
   241→                                {...childProps}
   242→                                className="block px-4 py-2.5 text-sm text-foreground/80 hover:text-accent hover:bg-muted/5 rounded-lg transition-colors no-underline whitespace-nowrap"
   243→                              >
   244→                                {getLabel(child.name, child.url)}
   245→                              </ChildComp>
   246→                            </Fragment>
   247→                          );
   248→                        })}
   249→                      </div>
   250→                    </div>
   251→                  </div>
   252→                );
   253→              }
   254→
   255→              return (
   256→                <Component
   257→                  key={item.url}
   258→                  href={item.url}
   259→                  {...props}
   260→                  className={`text-sm font-sans font-medium no-underline transition-colors duration-200 flex items-center gap-1 ${
   261→                    active ? 'text-accent' : 'text-foreground/80 hover:text-heading'
   262→                  }`}
   263→                >
   264→                  {getLabel(item.name, item.url)}
   265→                  {isExternal && (
   266→                    <svg
   267→                      width="12"
   268→                      height="12"
   269→                      viewBox="0 0 24 24"
   270→                      fill="none"
   271→                      stroke="currentColor"
   272→                      strokeWidth="2"
   273→                      strokeLinecap="round"
   274→                      strokeLinejoin="round"
   275→                      className="opacity-70"
   276→                    >
   277→                      <path d="M7 17l9.2-9.2M17 17V7H7" />
   278→                    </svg>
   279→                  )}
   280→                </Component>
   281→              );
   282→            })}
   283→          </div>
   284→          <div className="w-px h-4 bg-muted/20 mx-1 hidden md:block"></div>
   285→          {/* Hamburger button - mobile only */}
   286→          <button
   287→            className="md:hidden p-3 -mr-3 text-foreground/80 hover:text-heading transition-colors"
   288→            onClick={() => setIsMenuOpen(!isMenuOpen)}
   289→            aria-label={isMenuOpen ? 'Close menu' : 'Open menu'}
   290→            aria-expanded={isMenuOpen}
   291→          >
   292→            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   293→              {isMenuOpen ? (
   294→                <>
   295→                  <line x1="18" y1="6" x2="6" y2="18" />
   296→                  <line x1="6" y1="6" x2="18" y2="18" />
   297→                </>
   298→              ) : (
   299→                <>
   300→                  <line x1="3" y1="6" x2="21" y2="6" />
   301→                  <line x1="3" y1="12" x2="21" y2="12" />
   302→                  <line x1="3" y1="18" x2="21" y2="18" />
   303→                </>
   304→              )}
   305→            </svg>
   306→          </button>
   307→          <Search />
   308→          <LanguageSwitch />
   309→          <ThemeToggle />
   310→        </div>
   311→      </div>
   312→
   313→      {/* Mobile menu panel */}
   314→      {isMenuOpen && (
   315→        <>
   316→          {/* Backdrop */}
   317→          <div
   318→            className="fixed inset-0 top-16 bg-background/60 backdrop-blur-sm md:hidden"
   319→            onClick={() => closeMenu()}
   320→          />
   321→          {/* Menu */}
   322→          <div className="md:hidden absolute top-16 left-0 w-full bg-background/95 backdrop-blur-md border-b border-muted/10 shadow-lg animate-slide-down">
   323→            <div className="max-w-6xl mx-auto px-6 py-4 flex flex-col gap-1">
   324→              {navItems.map((item) => {
   325→                const isExternal = !!('external' in item && item.external);
   326→                const active = isActive(item.url);
   327→
   328→                // Series accordion for mobile
   329→                if (item.url === '/series' && seriesList.length > 0) {
   330→                  const isOpen = openDropdown === '/series';
   331→                  return (
   332→                    <div key={item.url}>
   333→                      <div className={`flex items-center rounded-lg transition-colors ${active ? 'text-accent' : 'text-foreground/80'}`}>
   334→                        <Link
   335→                          href={item.url}
   336→                          className="flex-1 px-3 py-3 text-base font-sans font-medium no-underline hover:text-accent transition-colors"
   337→                          onClick={() => closeMenu()}
   338→                        >
   339→                          {getLabel(item.name, item.url)}
   340→                        </Link>
   341→                        <button
   342→                          className="px-3 py-3 text-foreground/60 hover:text-accent transition-colors"
   343→                          onClick={() => setOpenDropdown(isOpen ? null : '/series')}
   344→                          aria-label={isOpen ? 'Collapse series list' : 'Expand series list'}
   345→                          aria-expanded={isOpen}
   346→                        >
   347→                          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={`transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}>
   348→                            <path d="M6 9l6 6 6-6"/>
   349→                          </svg>
   350→                        </button>
   351→                      </div>
   352→                      {isOpen && (
   353→                        <div className="ml-4 pl-3 border-l-2 border-muted/10 flex flex-col gap-1 mb-1">
   354→                          {seriesList.map(s => (
   355→                            <Link
   356→                              key={s.slug}
   357→                              href={`/series/${s.slug}`}
   358→                              className="block px-3 py-2 text-sm text-foreground/80 hover:text-accent hover:bg-muted/5 rounded-lg no-underline transition-colors"
   359→                              onClick={() => closeMenu()}
   360→                            >
   361→                              {s.name}
   362→                            </Link>
   363→                          ))}
   364→                          <Link
   365→                            href="/series"
   366→                            className="block px-3 py-2 text-xs font-bold uppercase tracking-widest text-muted hover:text-accent hover:bg-muted/5 rounded-lg no-underline transition-colors"
   367→                            onClick={() => closeMenu()}
   368→                          >
   369→                            {t('all_series')} →
   370→                          </Link>
   371→                        </div>
   372→                      )}
   373→                    </div>
   374→                  );
   375→                }
   376→
   377→                // Books accordion for mobile
   378→                if (item.url === '/books' && booksList.length > 0) {
   379→                  const isOpen = openDropdown === '/books';
   380→                  return (
   381→                    <div key={item.url}>
   382→                      <div className={`flex items-center rounded-lg transition-colors ${active ? 'text-accent' : 'text-foreground/80'}`}>
   383→                        <Link
   384→                          href={item.url}
   385→                          className="flex-1 px-3 py-3 text-base font-sans font-medium no-underline hover:text-accent transition-colors"
   386→                          onClick={() => closeMenu()}
   387→                        >
   388→                          {getLabel(item.name, item.url)}
   389→                        </Link>
   390→                        <button
   391→                          className="px-3 py-3 text-foreground/60 hover:text-accent transition-colors"
   392→                          onClick={() => setOpenDropdown(isOpen ? null : '/books')}
   393→                          aria-label={isOpen ? 'Collapse books list' : 'Expand books list'}
   394→                          aria-expanded={isOpen}
   395→                        >
   396→                          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={`transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}>
   397→                            <path d="M6 9l6 6 6-6"/>
   398→                          </svg>
   399→                        </button>
   400→                      </div>
   401→                      {isOpen && (
   402→                        <div className="ml-4 pl-3 border-l-2 border-muted/10 flex flex-col gap-1 mb-1">
   403→                          {booksList.map(b => (
   404→                            <Link
   405→                              key={b.slug}
   406→                              href={`/books/${b.slug}`}
   407→                              className="block px-3 py-2 text-sm text-foreground/80 hover:text-accent hover:bg-muted/5 rounded-lg no-underline transition-colors"
   408→                              onClick={() => closeMenu()}
   409→                            >
   410→                              {b.name}
   411→                            </Link>
   412→                          ))}
   413→                          <Link
   414→                            href="/books"
   415→                            className="block px-3 py-2 text-xs font-bold uppercase tracking-widest text-muted hover:text-accent hover:bg-muted/5 rounded-lg no-underline transition-colors"
   416→                            onClick={() => closeMenu()}
   417→                          >
   418→                            {t('all_books')} →
   419→                          </Link>
   420→                        </div>
   421→                      )}
   422→                    </div>
   423→                  );
   424→                }
   425→
   426→                // Static children accordion for mobile (e.g., "More")
   427→                if (item.children && item.children.length > 0) {
   428→                  const dropdownKey = item.url || item.name;
   429→                  const isOpen = openDropdown === dropdownKey;
   430→                  const childActive = item.children.some(c => c.url && pathname.startsWith(c.url));
   431→                  return (
   432→                    <div key={dropdownKey}>
   433→                      <button
   434→                        type="button"
   435→                        className={`w-full flex items-center justify-between px-3 py-3 text-base font-sans font-medium rounded-lg transition-colors ${
   436→                          childActive ? 'text-accent' : 'text-foreground/80 hover:text-accent hover:bg-muted/5'
   437→                        }`}
   438→                        onClick={() => setOpenDropdown(isOpen ? null : dropdownKey)}
   439→                        aria-expanded={isOpen}
   440→                      >
