async function getFontSizePx(page: Page, selector: string): Promise<number> {
  return page.evaluate((sel) => {
    const el = document.querySelector(sel);
    if (!el) return -1;
    return parseFloat(getComputedStyle(el).fontSize);
  }, selector);
